import { Directive, ElementRef, inject, input, model } from '@angular/core';

@Directive({
  selector: 'input[hbCurrency]',
  host: { '(input)': 'onInput()' },
  exportAs: 'hbCurrency',
})
export class HbCurrencyDirective {
  private readonly host = inject<ElementRef<HTMLInputElement>>(ElementRef);

  readonly hbCurrency = input('USD');
  readonly hbLocale = input<string | undefined>(undefined);
  readonly hbCurrencyValue = model<number | null>(null);

  protected onInput(): void {
    const el = this.host.nativeElement;
    const digits = el.value.replace(/\D/g, '');
    if (!digits) {
      el.value = '';
      this.hbCurrencyValue.set(null);
      return;
    }
    const amount = Number(digits) / 100;
    this.hbCurrencyValue.set(amount);
    el.value = new Intl.NumberFormat(this.hbLocale(), {
      style: 'currency',
      currency: this.hbCurrency(),
    }).format(amount);
  }
}

export * from './input.directive';
export * from './input.variants';
export * from './numeric.directive';
export * from './currency.directive';
export * from './mask.directive';

import { booleanAttribute, computed, Directive, ElementRef, inject, input } from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { inputVariants, type HbInputSize, type HbInputStatus } from './input.variants';

@Directive({
  selector: 'input[hb-input], textarea[hb-input]',
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'input'",
    '[attr.aria-invalid]': 'hbInvalid() || null',
    '[attr.data-status]': "hbStatus() !== 'default' ? hbStatus() : null",
  },
  exportAs: 'hbInput',
})
export class HbInputDirective {
  private readonly host = inject<ElementRef<HTMLElement>>(ElementRef);
  private readonly baseClass = this.host.nativeElement.getAttribute('class') ?? '';
  private readonly isTextarea = this.host.nativeElement.tagName === 'TEXTAREA';
  private readonly isFile =
    this.host.nativeElement.tagName === 'INPUT' &&
    this.host.nativeElement.getAttribute('type') === 'file';

  readonly hbSize = input<HbInputSize>('md');
  readonly hbStatus = input<HbInputStatus>('default');
  readonly hbInvalid = input(false, { transform: booleanAttribute });
  readonly hbBorderless = input(false, { transform: booleanAttribute });
  readonly hbRing = input(true, { transform: booleanAttribute });
  readonly hbFluid = input(false, { transform: booleanAttribute });
  readonly class = input<ClassValue>('');

  protected readonly classes = computed(() =>
    cn(
      inputVariants({
        size: this.hbSize(),
        status: this.hbStatus(),
        borderless: this.hbBorderless(),
        ring: this.hbRing(),
        fluid: this.hbFluid(),
      }),
      this.isTextarea ? 'field-sizing-content h-auto min-h-16 py-2' : '',
      this.isFile ? 'flex items-center cursor-pointer file:cursor-pointer' : '',
      this.baseClass,
      this.class(),
    ),
  );
}

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '{{alias}}/utils';

export const inputVariants = cva(
  cn(
    'min-w-0 rounded-md border border-input bg-background text-foreground shadow-xs',
    'outline-none transition-[color,box-shadow] placeholder:text-muted-foreground',
    'file:mr-2 file:border-0 file:bg-transparent file:text-sm file:font-medium file:text-foreground',
    'focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50',
    'disabled:cursor-not-allowed disabled:opacity-50',
    'aria-[invalid=true]:border-destructive aria-[invalid=true]:ring-destructive/20 aria-[invalid=true]:focus-visible:ring-destructive/30',
  ),
  {
    variants: {
      size: {
        xs: 'h-7 px-2 text-xs',
        sm: 'h-8 px-2.5 text-sm',
        md: 'h-9 px-3 text-sm',
        lg: 'h-10 px-3.5 text-base',
        xl: 'h-11 px-4 text-base',
      },
      status: {
        default: '',
        success: 'border-success focus-visible:border-success focus-visible:ring-success/30',
        warning: 'border-warning focus-visible:border-warning focus-visible:ring-warning/30',
        error: 'border-destructive focus-visible:border-destructive focus-visible:ring-destructive/30',
      },
      borderless: {
        true: 'rounded-none border-0 bg-transparent shadow-none focus-visible:ring-0',
        false: '',
      },
      ring: {
        true: '',
        false: 'focus-visible:ring-0 aria-[invalid=true]:focus-visible:ring-0',
      },
      fluid: { true: 'w-full', false: 'w-auto' },
    },
    defaultVariants: { size: 'md', status: 'default', borderless: false, ring: true, fluid: false },
  },
);

export type HbInputSize = NonNullable<VariantProps<typeof inputVariants>['size']>;
export type HbInputStatus = NonNullable<VariantProps<typeof inputVariants>['status']>;

import { Directive, ElementRef, inject, input } from '@angular/core';

@Directive({
  selector: 'input[hbMask]',
  host: { '(input)': 'onInput()' },
  exportAs: 'hbMask',
})
export class HbMaskDirective {
  private readonly host = inject<ElementRef<HTMLInputElement>>(ElementRef);

  readonly hbMask = input<string | RegExp>('');

  private lastValid = '';

  protected onInput(): void {
    const el = this.host.nativeElement;
    const mask = this.hbMask();
    if (!mask) return;
    const pattern = mask instanceof RegExp ? mask : new RegExp(mask);
    if (el.value === '' || pattern.test(el.value)) {
      this.lastValid = el.value;
    } else {
      el.value = this.lastValid;
    }
  }
}

import { booleanAttribute, Directive, ElementRef, inject, input } from '@angular/core';

export type HbNumericSign = 'both' | 'positive' | 'negative';

@Directive({
  selector: 'input[hbNumeric]',
  host: { '(input)': 'onInput()' },
  exportAs: 'hbNumeric',
})
export class HbNumericDirective {
  private readonly host = inject<ElementRef<HTMLInputElement>>(ElementRef);

  readonly hbSign = input<HbNumericSign>('both');
  readonly hbDecimal = input(false, { transform: booleanAttribute });

  private lastValid = '';

  protected onInput(): void {
    const el = this.host.nativeElement;
    let value = el.value;

    if (this.hbSign() === 'negative' && value && value !== '-' && !value.startsWith('-')) {
      value = `-${value}`;
    }

    if (value === '' || value === '-' || this.pattern().test(value)) {
      this.lastValid = value;
      if (el.value !== value) el.value = value;
    } else {
      el.value = this.lastValid;
    }
  }

  private pattern(): RegExp {
    const sign = this.hbSign();
    const signPart = sign === 'positive' ? '' : sign === 'negative' ? '-' : '-?';
    const decimal = this.hbDecimal() ? '(\\.\\d*)?' : '';
    return new RegExp(`^${signPart}\\d*${decimal}$`);
  }
}

