import { ChangeDetectionStrategy, Component, signal } from '@angular/core';

import {
  HbCurrencyDirective,
  HbInputDirective,
  HbMaskDirective,
  HbNumericDirective,
} from '@herbst/ui';

@Component({
  selector: 'hb-demo-input-directives',
  imports: [HbInputDirective, HbNumericDirective, HbCurrencyDirective, HbMaskDirective],
  template: `
    <div class="flex w-full max-w-sm flex-col gap-3">
      <input hb-input hbNumeric hbDecimal placeholder="Numeric — digits & one dot" />
      <input hb-input hbNumeric hbSign="negative" placeholder="Numeric — negative only" />

      <input
        hb-input
        hbCurrency="EUR"
        hbLocale="de-DE"
        [(hbCurrencyValue)]="amount"
        placeholder="Type digits: 12345 → €123,45"
      />
      <p class="font-mono text-[12px] text-muted-foreground">Value: {{ amount() ?? '—' }}</p>

      <input hb-input hbMask="^[A-Za-z]*$" placeholder="Mask — letters only" />
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoInputDirectivesComponent {
  protected readonly amount = signal<number | null>(null);
}

import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbInputDirective } from '@herbst/ui';

@Component({
  selector: 'hb-demo-input-sizes',
  imports: [HbInputDirective],
  template: `
    <div class="flex w-full max-w-sm flex-col gap-3">
      <input hb-input hbSize="xs" placeholder="Extra small" />
      <input hb-input hbSize="sm" placeholder="Small" />
      <input hb-input hbSize="md" placeholder="Medium (default)" />
      <input hb-input hbSize="lg" placeholder="Large" />
      <input hb-input hbSize="xl" placeholder="Extra large" />
      <input hb-input hbFluid placeholder="Fluid — fills its container" />
      <textarea hb-input hbFluid placeholder="Textarea auto-grows with content"></textarea>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoInputSizesComponent {}

import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbInputDirective } from '@herbst/ui';

@Component({
